import argparse
import sys
from urllib.parse import urlparse

import boto3
from botocore.exceptions import BotoCoreError, ClientError


ALLOWED_PROTOCOLS = {"https", "http", "email", "email-json", "sms", "sqs", "lambda", "application", "firehose"}


def parse_args():
    parser = argparse.ArgumentParser(description="Manage SNS subscriptions safely.")
    parser.add_argument("--topic-arn", required=True, help="SNS Topic ARN")
    parser.add_argument(
        "--protocol",
        default="https",
        choices=sorted(ALLOWED_PROTOCOLS),
        help="SNS subscription protocol",
    )
    parser.add_argument(
        "--endpoint",
        action="append",
        dest="endpoints",
        default=[],
        help="Subscription endpoint. Can be provided multiple times.",
    )
    parser.add_argument(
        "--endpoints-file",
        help="Path to a file containing one endpoint per line",
    )
    parser.add_argument(
        "--region",
        help="AWS region name",
    )
    return parser.parse_args()


def load_endpoints(args):
    endpoints = list(args.endpoints)
    if args.endpoints_file:
        with open(args.endpoints_file, "r", encoding="utf-8") as f:
            for line in f:
                value = line.strip()
                if value and not value.startswith("#"):
                    endpoints.append(value)

    if not endpoints:
        print("Enter subscription endpoints, one per line. Submit an empty line to finish:", file=sys.stderr)
        while True:
            try:
                value = input().strip()
            except EOFError:
                break
            if not value:
                break
            endpoints.append(value)

    return endpoints


def is_valid_endpoint(protocol, endpoint):
    if protocol in {"https", "http"}:
        try:
            parsed = urlparse(endpoint)
        except Exception:
            return False
        return parsed.scheme == protocol and bool(parsed.netloc)
    if protocol in {"email", "email-json"}:
        return "@" in endpoint and " " not in endpoint
    if protocol == "sms":
        return endpoint.startswith("+") and endpoint[1:].isdigit()
    if protocol in {"sqs", "lambda", "application", "firehose"}:
        return endpoint.startswith("arn:")
    return False


def subscribe_endpoints(topic_arn, protocol, endpoints, region=None):
    session = boto3.session.Session(region_name=region) if region else boto3.session.Session()
    sns = session.client("sns")

    results = []
    for endpoint in endpoints:
        if not is_valid_endpoint(protocol, endpoint):
            results.append((endpoint, None, "invalid endpoint format"))
            continue

        try:
            response = sns.subscribe(
                TopicArn=topic_arn,
                Protocol=protocol,
                Endpoint=endpoint,
                ReturnSubscriptionArn=True,
            )
            results.append((endpoint, response.get("SubscriptionArn"), None))
        except (BotoCoreError, ClientError) as e:
            results.append((endpoint, None, str(e)))
    return results


def main():
    args = parse_args()
    endpoints = load_endpoints(args)

    if not endpoints:
        print("No endpoints provided.", file=sys.stderr)
        sys.exit(1)

    results = subscribe_endpoints(args.topic_arn, args.protocol, endpoints, args.region)

    had_error = False
    for endpoint, arn, error in results:
        if error:
            had_error = True
            print(f"ERROR\t{endpoint}\t{error}")
        else:
            print(f"OK\t{endpoint}\t{arn}")

    if had_error:
        sys.exit(2)


if __name__ == "__main__":
    main()